   125→        public void Close()
   126→        {
   127→            if (!_running)
   128→            {
   129→                return;
   130→            }
   131→
   132→            _running = false;
   133→
   134→            try
   135→            {
   136→                if (_workThread != null)
   137→                {
   138→                    _workThread.Join(300);
   139→                }
   140→            }
   141→            catch
   142→            {
   143→            }
   144→
   145→            try
   146→            {
   147→                if (_rxThread != null)
   148→                {
   149→                    _rxThread.Join(300);
   150→                }
   151→            }
   152→            catch
   153→            {
   154→            }
   155→
   156→            if (_port.IsOpen)
   157→            {
   158→                _port.Close();
   159→            }
   160→
   161→            LogInfo("PLC CLOSE");
   162→        }
