   169→        // ===== 출력 제어 =====
   170→        public void Do_On(int bit)
   171→        {
   172→            if ((uint)bit >= 64u)
   173→            {
   174→                return;
   175→            }
   176→
   177→            lock (_outLock)
   178→            {
   179→                if (!_out[bit])
   180→                {
   181→                    _out[bit] = true;
   182→                    _outDirty = true;
   183→                    _outVersion++;
   184→                }
   185→            }
   186→        }
   187→
   188→        public void Do_Off(int bit)
   189→        {
   190→            if ((uint)bit >= 64u)
   191→            {
   192→                return;
   193→            }
   194→
   195→            lock (_outLock)
   196→            {
   197→                if (_out[bit])
   198→                {
   199→                    _out[bit] = false;
   200→                    _outDirty = true;
   201→                    _outVersion++;
   202→                }
   203→            }
   204→        }
   205→
   206→        // 같은 값이어도 재전송이 필요할 때(옵션)
   207→        public void Do_On_Force(int bit)
   208→        {
   209→            if ((uint)bit >= 64u)
   210→            {
   211→                return;
   212→            }
   213→
   214→            lock (_outLock)
   215→            {
   216→                _out[bit] = true;
   217→                _outDirty = true;
   218→                _outVersion++;
   219→            }
   220→        }
   221→
   222→        public void Do_Off_Force(int bit)
   223→        {
   224→            if ((uint)bit >= 64u)
   225→            {
   226→                return;
   227→            }
   228→
   229→            lock (_outLock)
   230→            {
   231→                _out[bit] = false;
   232→                _outDirty = true;
   233→                _outVersion++;
   234→            }
   235→        }
