   263→        public bool GetOutput(int bit)
   264→        {
   265→            if ((uint)bit >= 64u)
   266→            {
   267→                return false;
   268→            }
   269→
   270→            lock (_outLock)
   271→            {
   272→                return _out[bit];
   273→            }
   274→        }
   275→
   276→        public bool GetInput(int bit)
   277→        {
   278→            if ((uint)bit >= 64u)
   279→            {
   280→                return false;
   281→            }
   282→
   283→            return _in[bit];
   284→        }
