   396→        // ===== RX 누적/프레임 처리 =====
   397→        private void AppendRx(byte[] src, int len)
   398→        {
   399→            lock (_rxLock)
   400→            {
   401→                if (_rxAccumLen + len > _rxAccum.Length)
   402→                {
   403→                    var bigger = new byte[Math.Max(_rxAccum.Length * 2, _rxAccumLen + len)];
   404→                    Buffer.BlockCopy(_rxAccum, 0, bigger, 0, _rxAccumLen);
   405→                    _rxAccum = bigger;
   406→                }
   407→
   408→                Buffer.BlockCopy(src, 0, _rxAccum, _rxAccumLen, len);
   409→                _rxAccumLen += len;
   410→            }
   411→        }
   412→
   413→        private void ProcessFrames()
   414→        {
   415→            while (true)
   416→            {
   417→                int etxIndex;
   418→
   419→                lock (_rxLock)
   420→                {
   421→                    etxIndex = IndexOf(_rxAccum, 0, _rxAccumLen, ETX);
   422→                    if (etxIndex < 0)
   423→                    {
   424→                        return;
   425→                    }
   426→                }
   427→
   428→                string frame;
   429→
   430→                lock (_rxLock)
   431→                {
   432→                    frame = Encoding.ASCII.GetString(_rxAccum, 0, etxIndex + 1); // ETX 포함
   433→                    int remain = _rxAccumLen - (etxIndex + 1);
   434→
   435→                    if (remain > 0)
   436→                    {
   437→                        Buffer.BlockCopy(_rxAccum, etxIndex + 1, _rxAccum, 0, remain);
   438→                    }
   439→
   440→                    _rxAccumLen = remain;
   441→                }
   442→
   443→                if (EnableLog && VerboseTxRx)
   444→                {
   445→                    Log("RX " + frame);
   446→                }
   447→
   448→                if (!_waiting)
   449→                {
   450→                    continue; // 예상 응답이 아닐 때는 무시(필요시 큐잉)
   451→                }
   452→
   453→                try
   454→                {
   455→                    switch (_step)
   456→                    {
   457→                        case 1: // IN0 응답
   458→                            if (!TryParseInputs(frame, 0))
   459→                            {
   460→                                LogInfo("[WARN] IN0 parse fail");
   461→                            }
   462→                            _step = 2;
   463→                            break;
   464→
   465→                        case 3: // IN1 응답
   466→                            if (!TryParseInputs(frame, 32))
   467→                            {
   468→                                LogInfo("[WARN] IN1 parse fail");
   469→                            }
   470→                            _step = 4;
   471→                            break;
   472→
   473→                        case 5: // OUT0 ack
   474→                            _step = 6;
   475→                            break;
   476→
   477→                        case 7: // OUT1 ack
   478→                            // ★ 쓰기 사이클 시작 시점의 버전과 현재 버전이 같을 때만 Dirty 클리어
   479→                            lock (_outLock)
   480→                            {
   481→                                if (_writeCycleVersion == _outVersion)
   482→                                {
   483→                                    _outDirty = false;
   484→                                }
   485→                                // 다르면: 사이클 도중에 Commit이 한 번 더 들어왔다는 뜻 → Dirty 유지
   486→                            }
   487→                            _step = 0;
   488→                            break;
   489→                    }
   490→                }
   491→                finally
   492→                {
   493→                    ResetAwait();
   494→                    _consecutiveTimeouts = 0;
   495→                }
   496→            }
   497→        }
