    21→        /// <summary>
    22→        /// 연결 문자열에서 서버 주소 추출 (public wrapper)
    23→        /// </summary>
    24→        public static string GetServerAddress(string connectionString)
    25→        {
    26→            return ExtractServerFromConnectionString(connectionString);
    27→        }
