    29→        /// <summary>
    30→        /// 연결 문자열에서 서버 주소 추출
    31→        /// </summary>
    32→        private static string ExtractServerFromConnectionString(string connectionString)
    33→        {
    34→            if (string.IsNullOrWhiteSpace(connectionString))
    35→                return null;
    36→
    37→            // Data Source=xxx 또는 Server=xxx 패턴 찾기 (공백 허용)
    38→            var match = Regex.Match(connectionString, @"(?:Data\s*Source|Server)\s*=\s*([^;]+)", RegexOptions.IgnoreCase);
    39→            if (match.Success)
    40→            {
    41→                string server = match.Groups[1].Value.Trim();
    42→                // 포트 번호 제거 (예: 192.168.1.100,1433 → 192.168.1.100)
    43→                int commaIdx = server.IndexOf(',');
    44→                if (commaIdx > 0)
    45→                    server = server.Substring(0, commaIdx).Trim();
    46→                return server;
    47→            }
    48→            return null;
    49→        }
    50→
    51→        /// <summary>
    52→        /// 서버 핑 체크 (타임아웃 1초)
    53→        /// 연결 문자열 또는 서버 주소를 받을 수 있음
    54→        /// </summary>
    55→        public static bool IsServerReachable(string serverOrConnectionString, int timeoutMs = 1000)
    56→        {
    57→            if (string.IsNullOrWhiteSpace(serverOrConnectionString))
    58→                return false;
    59→
    60→            // 연결 문자열인 경우 서버 주소 추출
    61→            string server = serverOrConnectionString;
    62→            if (serverOrConnectionString.Contains("="))
    63→            {
    64→                server = ExtractServerFromConnectionString(serverOrConnectionString);
    65→            }
    66→
    67→            if (string.IsNullOrWhiteSpace(server))
    68→                return false;
    69→
    70→            try
    71→            {
    72→                using (var ping = new Ping())
    73→                {
    74→                    var reply = ping.Send(server, timeoutMs);
    75→                    return reply.Status == IPStatus.Success;
    76→                }
    77→            }
    78→            catch
    79→            {
    80→                return false;
    81→            }
    82→        }
