   102→
   103→                // 서버 핑 체크 (프리징 방지) - 타임아웃 1초
   104→                if (!IsServerReachable(server, 1000))
   105→                {
   106→                    logger?.Invoke($"[SQL] SQL Server ({server}) 연결 불가 - 건너뜀");
   107→                    return;
   108→                }
   109→
   110→                // config.ini에서 이미 확인했는지 체크 (성능 최적화)
