   112→                IniFile ini = new IniFile("config.ini");
   113→                string sqlServerStructureChecked = ini.ReadValue("Database", "SqlServerTableStructureChecked");
   114→                string checkedVersion = ini.ReadValue("Database", "SqlServerStructureVersion");
   115→
