    95→            catch (NationalInstruments.DAQmx.DaqException ex)
    96→            {
    97→                // 장치가 없거나 지원되지 않을 때
    98→                _log?.Invoke($"DAQ 장치 없음 (채널 {_phys[i]}) → 시뮬레이션 모드로 전환: {ex.Message}");
    99→                continue; // 그냥 다음 채널로 넘어감
   100→            }
   101→            catch (Exception ex)
   102→            {
   103→                _log?.Invoke($"[ERR] 채널 생성 실패: {ex.Message}");
   104→                continue;
   105→            }            
   106→        }
   107→
   108→    }
   109→    private void ReadCallback(IAsyncResult ar)
   110→    {
   111→        try
   112→        {
   113→            if (_task == null || ar.AsyncState != _task) return;
   114→
   115→            var data = _reader.EndReadWaveform(ar);
   116→
   117→            WaveformAvailable?.Invoke(data);
   118→
   119→            double[] db = ComputeDbFromVolt(data);
   120→
   121→            // 첫 번째 채널 값만 Value에 저장 (소수점 둘째 자리)
   122→            if (db.Length > 0)
   123→                Value = Math.Round(db[0], 2);
   124→
   125→            DbAvailable?.Invoke(db);
   126→
   127→            _recycle = data;
   128→            _reader.BeginMemoryOptimizedReadWaveform(_samplesPerRead, _cb, _task, _recycle);
   129→        }
   130→        catch (DaqException ex)
   131→        {
   132→            Log("DAQ 에러: " + ex.Message);
   133→            Stop();
   134→        }
   135→        catch (Exception ex)
   136→        {
   137→            Log("예외: " + ex.Message);
   138→            Stop();
   139→        }
   140→    }
   141→    private static double[] ComputeDbFromVolt(AnalogWaveform<double>[] waveforms)
   142→    {
   143→        double[] result = new double[waveforms.Length];
   144→
   145→        for (int ch = 0; ch < waveforms.Length; ch++)
   146→        {
   147→            var w = waveforms[ch];
   148→            double sum = 0.0;
   149→            int n = w.Samples.Count;
   150→
   151→            if (n == 0)
   152→            {
   153→                result[ch] = double.NegativeInfinity;
   154→                continue;
   155→            }
   156→
   157→            for (int i = 0; i < n; i++)
   158→                sum += w.Samples[i].Value; // Volt
   159→
   160→            double vAvg = sum / n;   // 단순 평균 전압
   161→            result[ch] = vAvg * 100; // dB 변환 (샘플 규칙)
   162→        }
   163→
   164→        return result;
   165→    }
   166→    public void Stop()
   167→    {
   168→        try
   169→        {
   170→            if (_task != null)
   171→            {
   172→                _task.Stop();
   173→                _task.Dispose();
   174→                _task = null;
   175→                _reader = null;
   176→                _cb = null;
   177→                _recycle = null;
   178→                Value = 0;
   179→
   180→                Log("DAQ 중지");
   181→            }
   182→        }
   183→        catch (DaqException ex)
   184→        {
   185→            Log("Stop 중 DAQ 예외: " + ex.Message);
   186→        }
   187→    }
   188→    public void Dispose()
   189→    {
   190→        Stop();
   191→    }
   192→    private void Log(string s)
   193→    {
   194→        if (EnableLog) // 플래그 체크
   195→            _log?.Invoke(s);
   196→    }
   197→}
