   168→    // Manual request
   169→    public void RequestMeasurement()
   170→    {
   171→        if (!_port.IsOpen) return;
   172→
   173→        lock (_sync)
   174→        {
   175→            if (_awaitingResponse) return;
   176→
   177→            try
   178→            {
   179→                // :READ? 명령은 현재 레인지 설정을 유지하므로
   180→                // 첫 번째 요청 시에만 레인지 설정 (또는 Open 시에 설정)
   181→                // 측정 요청
   182→                _port.Write(QueryCommand);
   183→                _port.Write(LineTerminator);
   184→                _lastRequestUtc = DateTime.UtcNow;   // 요청 시각 저장
   185→                _awaitingResponse = true;
   186→            }
   187→            catch (Exception ex)
   188→            {
   189→                _awaitingResponse = false;
   190→                RaiseError("Write failed: " + ex.Message);
   191→            }
   192→        }
   193→    }
