   195→    // Timer tick
   196→    private void OnPollTimerElapsed(object sender, ElapsedEventArgs e)
   197→    {
   198→        if (!_port.IsOpen)
   199→            return;
   200→
   201→        bool shouldSendNew = false;
   202→        bool shouldRetryTimeout = false;
   203→
   204→        lock (_sync)
   205→        {
   206→            if (!_awaitingResponse)
   207→            {
   208→                // 이전 요청에 대한 응답 처리 완료 → 새 요청
   209→                shouldSendNew = true;
   210→            }
   211→            else
   212→            {
   213→                // 응답 대기 중인데 1초(ReadTimeout) 넘었으면 타임아웃 처리 후 재요청
   214→                double elapsedMs = (DateTime.UtcNow - _lastRequestUtc).TotalMilliseconds;
   215→                if (elapsedMs >= _port.ReadTimeout)
   216→                {
   217→                    _awaitingResponse = false;
   218→                    shouldRetryTimeout = true;
   219→                }
   220→            }
   221→        }
   222→
   223→        if (shouldSendNew)
   224→        {
   225→            RequestMeasurement();
   226→        }
   227→        else if (shouldRetryTimeout)
   228→        {
   229→            RaiseError("Response timeout (>= 1s). Retrying request.");
   230→            RequestMeasurement();
   231→        }
   232→    }
   233→
   234→    // DataReceived
   235→    private void OnPortDataReceived(object sender, SerialDataReceivedEventArgs e)
   236→    {
   237→        try
   238→        {
   239→            while (_port.IsOpen && _port.BytesToRead > 0)
   240→            {
   241→                string line = SafeReadLine();
   242→                if (line == null)
   243→                    break;
   244→
   245→                RaiseRaw(line);
   246→
   247→                string trimmed = line.Trim('\r', '\n', ' ');
   248→
   249→                double value;
   250→                bool parsed = TryParseResistance(trimmed, out value);
   251→
   252→                if (parsed)
   253→                {
   254→                    LastResistanceOhms = value;
   255→                    RaiseMeasured(value);
   256→                }
   257→
   258→                _awaitingResponse = false;
   259→            }
   260→        }
   261→        catch (TimeoutException)
   262→        {
   263→            _awaitingResponse = false;
   264→            RaiseError("Read timeout.");
   265→        }
   266→        catch (Exception ex)
   267→        {
   268→            _awaitingResponse = false;
   269→            RaiseError("Read failed: " + ex.Message);
   270→        }
   271→    }
   272→
   273→    // Parsing logic
   274→    private bool TryParseResistance(string s, out double value)
   275→    {
   276→        if (s.IndexOf("E+30", StringComparison.OrdinalIgnoreCase) >= 0)
   277→        {
   278→            value = -10.0;
   279→            return true;
   280→        }
   281→
   282→        if (double.TryParse(
   283→            s,
   284→            NumberStyles.Float | NumberStyles.AllowThousands,
   285→            CultureInfo.InvariantCulture,
   286→            out value))
   287→        {
   288→            return true;
   289→        }
   290→
   291→        int ePos = s.IndexOf('E');
   292→        if (ePos > 0)
   293→        {
   294→            string head = s.Substring(0, ePos);
   295→            if (double.TryParse(
   296→                head,
   297→                NumberStyles.Float,
   298→                CultureInfo.InvariantCulture,
   299→                out value))
   300→            {
   301→                return true;
   302→            }
   303→        }
   304→
   305→        value = double.NaN;
   306→        return false;
   307→    }
   308→
   309→    private string SafeReadLine()
   310→    {
   311→        try
   312→        {
   313→            return _port.ReadLine();
   314→        }
   315→        catch (TimeoutException)
   316→        {
   317→            return null;
   318→        }
   319→    }
   320→
   321→    // Event helpers (UI 컨텍스트로 마샬링)
