    14→    private Thread _rxThread;
    15→    private volatile bool _running;
    16→
    17→    // 바이너리 프로토콜 상수
    18→    private const byte HEADER = 0x55;
    19→    private const byte CMD_ANGLE = 0x53;  // 각도 데이터 (X, Y, Z)
    20→    private const int ANGLE_PACKET_LENGTH = 11;  // 헤더(1) + CMD(1) + 데이터(6) + 체크섬(1) + 예비(2)
    21→
