    58→
    59→        try
    60→        {
    61→            if (!_port.IsOpen)
    62→            {
    63→                _port.Open();
    64→            }
    65→        }
    66→        catch (Exception ex)
    67→        {
    68→            Log($"SerialAngle 포트 열기 실패: {ex.Message}");
    69→            return;
    70→        }
