   109→                return false;
   110→            }
   111→
   112→            _portName = portName;
   113→            _receiveCount = 0;
   114→            _parseSuccessCount = 0;
   115→            _parseFailCount = 0;
   116→            _buffer.Clear();
   117→
   118→            _serialPort = new SerialPort(portName, 921600, Parity.None, 8, StopBits.One)
   119→            {
   120→                DtrEnable = false,
   121→                RtsEnable = false,
   122→                ReadTimeout = 100,
   123→                ReadBufferSize = 8192,
   124→                WriteBufferSize = 1024
   125→            };
   126→
   127→            _serialPort.Open();
   128→            Log($"포트 열림 OK");
   129→
   130→            _isConnected = true;
   131→            _keepReading = true;
   132→
   133→            _readThread = new Thread(ReadSerialThread) { IsBackground = true };
   134→            _readThread.Start();
   135→
   136→            StartReconnectMonitor();
   137→            LoadOffset();
   138→            return true;
   139→        }
   140→        catch (Exception ex)
   141→        {
   142→            Log($"Connect 예외: {ex.GetType().Name} - {ex.Message}");
   143→            _isConnected = false;
   144→            _serialPort?.Dispose();
   145→            _serialPort = null;
   146→            return false;
   147→        }
   148→    }
   149→
   150→    /// <summary>연결 해제</summary>
   151→    public void Disconnect()
   152→    {
   153→        Log($"Disconnect - 수신:{_receiveCount}, 파싱성공:{_parseSuccessCount}, 실패:{_parseFailCount}");
   154→        StopReconnectMonitor();
   155→        DisconnectInternal();
   156→    }
   157→
   158→    private void DisconnectInternal()
   159→    {
   160→        _keepReading = false;
   161→
   162→        _readThread?.Join(500);
   163→        _readThread = null;
   164→
   165→        if (_serialPort != null)
   166→        {
   167→            try { if (_serialPort.IsOpen) _serialPort.Close(); _serialPort.Dispose(); }
   168→            catch (Exception ex) { Log($"포트 해제 예외: {ex.Message}"); }
   169→            _serialPort = null;
   170→        }
   171→        _isConnected = false;
   172→    }
   173→
   174→    private void StartReconnectMonitor()
   175→    {
   176→        if (_reconnectThread != null && _reconnectThread.IsAlive) return;
   177→        _keepReconnecting = true;
   178→        _reconnectThread = new Thread(ReconnectMonitorThread) { IsBackground = true };
   179→        _reconnectThread.Start();
   180→    }
   181→
   182→    private void StopReconnectMonitor()
   183→    {
   184→        _keepReconnecting = false;
   185→        _reconnectThread?.Join(1000);
   186→        _reconnectThread = null;
   187→    }
   188→
   189→    private void ReconnectMonitorThread()
   190→    {
   191→        while (_keepReconnecting)
   192→        {
   193→            try
   194→            {
   195→                Thread.Sleep(2000);
   196→                if (!_keepReconnecting) break;
   197→
   198→                bool needReconnect = _serialPort == null || !_serialPort.IsOpen || !_isConnected;
   199→                if (needReconnect && !string.IsNullOrEmpty(_portName) && _portName != "Disabled")
   200→                {
   201→                    Log($"재연결 시도: {_portName}");
   202→                    DisconnectInternal();
   203→                    Thread.Sleep(1000);
   204→                    if (TryReconnect()) Log("재연결 성공");
   205→                }
   206→            }
   207→            catch (Exception ex) { Log($"재연결 모니터 예외: {ex.Message}"); }
   208→        }
   209→    }
   210→
   211→    private bool TryReconnect()
   212→    {
   213→        try
   214→        {
   215→            if (string.IsNullOrEmpty(_portName) || _portName == "Disabled") return false;
   216→            bool found = false;
   217→            foreach (var p in SerialPort.GetPortNames()) if (p == _portName) { found = true; break; }
   218→            if (!found) return false;
   219→
   220→            _buffer.Clear();
   221→            _serialPort = new SerialPort(_portName, 921600, Parity.None, 8, StopBits.One)
   222→            {
   223→                DtrEnable = false, RtsEnable = false,
   224→                ReadTimeout = 100, ReadBufferSize = 8192
   225→            };
   226→            _serialPort.Open();
   227→
   228→            if (_serialPort.IsOpen)
   229→            {
   230→                _isConnected = true;
   231→                _keepReading = true;
   232→                _readThread = new Thread(ReadSerialThread) { IsBackground = true };
   233→                _readThread.Start();
   234→                LoadOffset();
   235→                return true;
   236→            }
   237→            return false;
   238→        }
   239→        catch (Exception ex)
   240→        {
   241→            Log($"TryReconnect 예외: {ex.Message}");
   242→            try { _serialPort?.Dispose(); } catch { }
   243→            _serialPort = null;
   244→            _isConnected = false;
   245→            return false;
   246→        }
   247→    }
   248→
   249→    #endregion
   250→
   251→    #region 명령 전송
   252→
   253→    /// <summary>카운트를 0으로 리셋 (NVS 미저장)</summary>
   254→    public void SendZero() => SendCommand("ZERO");
   255→
   256→    /// <summary>현재 위치를 절대 원점으로 NVS 저장</summary>
   257→    public void SendSetHome() => SendCommand("SETHOME");
   258→
   259→    /// <summary>현재 상태 즉시 출력 요청</summary>
   260→    public void SendStatus() => SendCommand("STATUS");
   261→
   262→    /// <summary>임의 명령 전송</summary>
   263→    public void SendCommand(string cmd)
   264→    {
   265→        try
   266→        {
   267→            if (_isConnected && _serialPort != null && _serialPort.IsOpen)
   268→            {
   269→                Log($"SendCommand: {cmd}");
   270→                _serialPort.WriteLine(cmd);
   271→            }
   272→            else
   273→            {
   274→                Log($"SendCommand 실패 (연결안됨): {cmd}");
   275→            }
   276→        }
   277→        catch (Exception ex) { Log($"SendCommand 예외: {ex.Message}"); }
   278→    }
   279→
   280→    #endregion
   281→
   282→    #region 시리얼 읽기/파싱
   283→
   284→    private void ReadSerialThread()
   285→    {
   286→        while (_keepReading && _serialPort != null && _serialPort.IsOpen)
   287→        {
   288→            try
   289→            {
   290→                int bytesToRead = _serialPort.BytesToRead;
   291→
   292→                if (bytesToRead > 4096)
   293→                {
   294→                    Log($"버퍼 오버플로우({bytesToRead}), 클리어");
   295→                    _serialPort.DiscardInBuffer();
   296→                    _buffer.Clear();
   297→                    continue;
   298→                }
   299→
   300→                if (bytesToRead == 0) { Thread.Sleep(5); continue; }
   301→
   302→                string incoming = _serialPort.ReadExisting();
   303→                if (string.IsNullOrEmpty(incoming)) { Thread.Sleep(5); continue; }
   304→
   305→                _receiveCount++;
   306→                _buffer.Append(incoming);
   307→
   308→                // 줄 단위 추출
   309→                string data = _buffer.ToString();
   310→                int lastNl = data.LastIndexOf('\n');
   311→                if (lastNl < 0) lastNl = data.LastIndexOf('\r');
   312→                if (lastNl < 0) continue;
   313→
   314→                string complete = data.Substring(0, lastNl);
   315→                _buffer.Clear();
   316→                _buffer.Append(data.Substring(lastNl + 1));
   317→
   318→                foreach (string line in complete.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries))
   319→                {
   320→                    string t = line.Trim();
   321→                    if (t.StartsWith("{") && t.EndsWith("}"))
   322→                        ParseJson(t);
   323→                }
   324→            }
   325→            catch (TimeoutException) { }
   326→            catch (InvalidOperationException ex) { Log($"연결 끊김: {ex.Message}"); _isConnected = false; break; }
   327→            catch (System.IO.IOException ex)     { Log($"케이블 분리: {ex.Message}"); _isConnected = false; break; }
   328→            catch (Exception ex)                 { Log($"ReadThread 예외: {ex.GetType().Name} - {ex.Message}"); _isConnected = false; }
   329→        }
   330→    }
   331→
   332→    /// <summary>
   333→    /// JSON 파싱
   334→    /// 실시간 데이터: {"t":12345,"cnt":2048,"deg":180.00,"ok":true}
   335→    /// 명령 응답: {"cmd":"ZERO","ok":true} 등 → 로그만 출력
   336→    /// </summary>
   337→    private void ParseJson(string json)
   338→    {
   339→        try
   340→        {
   341→            // 명령 응답은 로그만
   342→            if (json.Contains("\"cmd\""))
   343→            {
   344→                Log($"CMD 응답: {json}");
   345→                return;
   346→            }
   347→
   348→            // 부팅 메시지
   349→            if (json.Contains("\"msg\""))
   350→            {
   351→                Log($"부팅: {json}");
   352→                return;
   353→            }
   354→
   355→            // 실시간 데이터: "deg" 필드 추출
   356→            double deg = 0;
   357→            int cnt = 0;
   358→            bool parsedDeg = false;
   359→
   360→            int degIdx = json.IndexOf("\"deg\":");
   361→            if (degIdx >= 0)
   362→            {
   363→                int start = degIdx + 6;
   364→                int end = json.IndexOfAny(new[] { ',', '}' }, start);
   365→                if (end > start)
   366→                    parsedDeg = double.TryParse(
   367→                        json.Substring(start, end - start).Trim(),
   368→                        System.Globalization.NumberStyles.Any,
   369→                        System.Globalization.CultureInfo.InvariantCulture, out deg);
   370→            }
   371→
   372→            if (!parsedDeg)
   373→            {
   374→                _parseFailCount++;
   375→                if (_parseFailCount <= 10) Log($"파싱 실패 #{_parseFailCount}: [{json}]");
   376→                return;
   377→            }
   378→
   379→            // cnt 필드 추출 (선택)
   380→            int cntIdx = json.IndexOf("\"cnt\":");
   381→            if (cntIdx >= 0)
   382→            {
   383→                int start = cntIdx + 6;
   384→                int end = json.IndexOfAny(new[] { ',', '}' }, start);
   385→                if (end > start)
   386→                    int.TryParse(json.Substring(start, end - start).Trim(), out cnt);
   387→            }
   388→
   389→            _parseSuccessCount++;
   390→
   391→            lock (_lock)
   392→            {
   393→                _degree = deg;
   394→                _count  = cnt - _offsetCount;
   395→            }
   396→
   397→            // 이벤트 발생 (UI 업데이트용)
   398→            AngleReceived?.Invoke(deg, cnt - _offsetCount);
   399→        }
   400→        catch (Exception ex)
   401→        {
   402→            _parseFailCount++;
   403→            Log($"ParseJson 예외: {ex.Message}, JSON=[{json}]");
   404→        }
   405→    }
   406→
   407→    #endregion
   408→
   409→    #region 원점 오프셋 저장/로드
   410→
   411→    /// <summary>현재 카운트를 원점(0)으로 설정 (프로그램 내 오프셋, NVS 미저장)</summary>
   412→    public void SetProgramHome()
   413→    {
   414→        lock (_lock) { _offsetCount = _count + _offsetCount; }
   415→        SaveOffset();
   416→        Log($"[프로그램 원점] offset={_offsetCount}");
   417→    }
   418→
   419→    private void SaveOffset()
   420→    {
   421→        try
   422→        {
   423→            if (string.IsNullOrEmpty(_encoderName)) return;
   424→            string iniPath = System.AppDomain.CurrentDomain.BaseDirectory + "config.ini";
   425→            var ini = new IniFile(iniPath);
   426→            ini.WriteValue($"Encoder_{_encoderName}", "OffsetCount", _offsetCount.ToString());
   427→            Log($"[오프셋 저장] offset={_offsetCount}");
   428→        }
   429→        catch (Exception ex) { Log($"SaveOffset 예외: {ex.Message}"); }
   430→    }
   431→
   432→    private void LoadOffset()
   433→    {
   434→        try
   435→        {
   436→            if (string.IsNullOrEmpty(_encoderName)) return;
   437→            string iniPath = System.AppDomain.CurrentDomain.BaseDirectory + "config.ini";
   438→            var ini = new IniFile(iniPath);
   439→            string s = ini.ReadValue($"Encoder_{_encoderName}", "OffsetCount");
   440→            if (!string.IsNullOrEmpty(s) && int.TryParse(s, out int o))
   441→            {
   442→                lock (_lock) { _offsetCount = o; }
   443→                Log($"[오프셋 로드] offset={o}");
   444→            }
   445→        }
   446→        catch (Exception ex) { Log($"LoadOffset 예외: {ex.Message}"); }
   447→    }
   448→
   449→    #endregion
   450→
   451→    public void Dispose() => Disconnect();
   452→}
