     1→using System;
     2→using System.Globalization;
     3→using System.IO.Ports;
     4→using System.Text;
     5→using System.Text.RegularExpressions;
     6→using System.Threading;
     7→
     8→public sealed class Ri20wStandard : IDisposable
     9→{
    10→    private readonly SerialPort _port;
    11→    private readonly Action<string> _log;
    12→    private Thread _rxThread;
    13→    private volatile bool _running;
    14→
    15→    private int _frameCount = 0;
    16→    private DateTime _lastFpsLogTime = DateTime.UtcNow;
    17→    private DateTime _lastResponseTime = DateTime.UtcNow;
    18→
    19→    public bool EnableLog { get; set; } = true;
    20→    public int DeviceId { get; }
    21→
    22→    // ✅ 최신값 (숫자 + 단위)
    23→    public double Value = double.NaN;
    24→    public string Unit = "";
    25→
    26→    // 이벤트
    27→    public event Action<double, string> ValueReceived; // (값, 단위)
    28→    public event Action<string> RawReceived;          // 원문
    29→
    30→    private static readonly Regex NumUnitRegex = new Regex(
    31→        @"([+-]?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)([A-Za-z%µ]*)",
    32→        RegexOptions.Compiled | RegexOptions.CultureInvariant
    33→    );
    34→
    35→    public Ri20wStandard(string portName, int deviceId = 1, Action<string> logger = null)
    36→    {
    37→        if (deviceId < 1 || deviceId > 99)
    38→            throw new ArgumentOutOfRangeException(nameof(deviceId), "DeviceId는 1~99");
    39→
    40→        DeviceId = deviceId;
    41→        _log = logger;
    42→
    43→        _port = new SerialPort(portName, 57600, Parity.None, 8, StopBits.One)
    44→        {
    45→            Encoding = Encoding.ASCII,
    46→            NewLine = "\r\n",
    47→            ReadTimeout = 50,
    48→            WriteTimeout = 50
    49→        };
    50→    }
    51→
    52→    public void Start()
    53→    {
    54→        if (_running) return;
    55→
    56→        try
    57→        {
    58→            _port.Open();
    59→        }
    60→        catch (Exception ex)
    61→        {
    62→            Log($"RI-20W[{DeviceId:D2}] 포트 열기 실패: {ex.Message}");
    63→            return; // 실행은 계속, 장비는 미시작 상태
    64→        }
    65→
    66→        _running = true;
    67→        _rxThread = new Thread(ReadLoop) { IsBackground = true };
    68→        _rxThread.Start();
    69→        Log($"RI-20W[{DeviceId:D2}] 시작 (57600bps)");
    70→
    71→        RequestValue(); // 최초 트리거
    72→    }
    73→
    74→
    75→    public void Stop()
    76→    {
    77→        _running = false;
    78→        try { if (_port.IsOpen) _port.Close(); } catch { }
    79→        Log($"RI-20W[{DeviceId:D2}] 통신 중지");
    80→    }
    81→
    82→    public void Dispose() => Stop();
    83→
    84→    private void ReadLoop()
    85→    {
    86→        var sb = new StringBuilder(256);
    87→
    88→        try
    89→        {
    90→            while (_running && _port.IsOpen)
    91→            {
    92→                string chunk = _port.ReadExisting();
    93→                if (chunk.Length > 0)
    94→                {
    95→                    sb.Append(chunk);
    96→                    int idx;
    97→                    while ((idx = sb.ToString().IndexOf("\r\n", StringComparison.Ordinal)) >= 0)
    98→                    {
    99→                        string line = sb.ToString(0, idx).Trim();
   100→                        sb.Remove(0, idx + 2);
   101→                        if (line.Length == 0) continue;
   102→                        ParseLine(line);
   103→                    }
   104→                }
   105→                else
   106→                {
   107→                    if ((DateTime.UtcNow - _lastResponseTime).TotalSeconds > 1.0)
   108→                    {
   109→                        Log($"경고: ID{DeviceId:D2} 1초 이상 응답 없음 → 재요청");
   110→                        RequestValue();
   111→                        _lastResponseTime = DateTime.UtcNow;
   112→                    }
   113→                    Thread.Sleep(1);
   114→                }
   115→            }
   116→        }
   117→        catch (Exception ex)
   118→        {
   119→            Log($"수신 오류(ID{DeviceId:D2}): {ex.Message}");
   120→        }
   121→    }
   122→
   123→    private void ParseLine(string line)
   124→    {
   125→        RawReceived?.Invoke(line);
   126→
   127→        _frameCount++;
   128→        var now = DateTime.UtcNow;
   129→        if ((now - _lastFpsLogTime).TotalSeconds >= 1.0)
   130→        {
   131→            Log($"RX ID{DeviceId:D2}: {_frameCount} frames/sec");
   132→            _frameCount = 0;
   133→            _lastFpsLogTime = now;
   134→        }
   135→
   136→        // 표준 응답 예: "ID,01,+00123.4kg"
   137→        string[] parts = line.Split(',');
   138→        if (parts.Length >= 3)
   139→        {
   140→            string valStr = parts[2].Trim();
   141→            var match = NumUnitRegex.Match(valStr);
   142→            if (match.Success)
   143→            {
   144→                if (double.TryParse(match.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double val))
   145→                {
   146→                    string unit = match.Groups[2].Value;
   147→                    Value = val;
   148→                    Unit = unit;
   149→                    ValueReceived?.Invoke(val, unit);
   150→                }
   151→            }
   152→        }
   153→
   154→        _lastResponseTime = now;
   155→        if (_running) RequestValue();
   156→    }
   157→
   158→    public void RequestValue()
   159→    {
   160→        if (!_port.IsOpen) return;
   161→        string cmd = $"ID{DeviceId:D2}P\r\n";
   162→        _port.Write(cmd);
   163→        Log("TX: " + cmd.Trim());
   164→    }
   165→
   166→    public void SetZero()
   167→    {
   168→        if (!_port.IsOpen) return;
   169→        string cmd = $"ID{DeviceId:D2}Z\r\n";
   170→        _port.Write(cmd);
   171→        Log("TX: " + cmd.Trim());
   172→    }
   173→
   174→    private void Log(string s)
   175→    {
   176→        if (EnableLog && _log != null)
   177→            _log(s);
   178→    }
   179→}
