                "E" + "" + GS +
                "T" + gYMD + _4M_CODE + "A" + gLot + GS +
                "M" + "" + GS +
                "C" + tmpTestData + GS +
                RS + EOT;

            gBarcodeTMp = "T" + gYMD + _4M_CODE + "A" + gLot;
            gEndBarcode = TMP1;

            // ZPL 명령 생성
            string[] zplCommands = new[]
