                "^XA",
                $"^FO{GlobalValuesAdapter.BarcodeBX},{GlobalValuesAdapter.BarcodeBY}^BY5^BXN,{GlobalValuesAdapter.BarcodeBH},200,,,,^FH^FD{gEndBarcode}^FS",
                $"^FO{GlobalValuesAdapter.BarcodeS1X},{GlobalValuesAdapter.BarcodeS1Y}^A0N,{GlobalValuesAdapter.BarcodeS1H},{GlobalValuesAdapter.BarcodeS1W}^FD{gPartNo}^FS",
                $"^FO{GlobalValuesAdapter.BarcodeS2X},{GlobalValuesAdapter.BarcodeS2Y}^A0N,{GlobalValuesAdapter.BarcodeS2H},{GlobalValuesAdapter.BarcodeS2W}^FD{gYMD}{gLot}^FS",
