        private static string MidString(string s, int start1Based, int length)
        {
            if (string.IsNullOrEmpty(s) || length <= 0) return string.Empty;
            int start = Math.Max(0, start1Based - 1);
            if (start >= s.Length) return string.Empty;
            if (start + length > s.Length) length = s.Length - start;
            return s.Substring(start, length);
        }
        private string Asc2PrintStr(string str)
        {
            if (string.IsNullOrEmpty(str) || str.Length <= 2)
                return string.Empty;

            const string RS = "_1e";
            const string GS = "_1d";
            const string EOT = "_04";
            var sb = new StringBuilder(str.Length * 2);
            foreach (char ch in str)
            {
                int code = ch;
                switch (code)
                {
                    case 4: sb.Append(EOT); break;
                    case 30: sb.Append(RS); break;
                    case 29: sb.Append(GS); break;
                    default: sb.Append(ch); break;
                }
            }
            if (sb.Length == 0)
                return string.Empty;

            return "#" + sb.ToString();
        }

