        private static void EnsureColumnExists(OleDbConnection conn, string table, string column, string type)
        {
            // Access 스키마 조회
            var restrictions = new object[] { null, null, table, column };
            using (var schema = conn.GetOleDbSchemaTable(OleDbSchemaGuid.Columns, restrictions))
            {
                if (schema == null || schema.Rows.Count == 0)
                {
                    using (var cmd = new OleDbCommand($"ALTER TABLE [{table}] ADD COLUMN [{column}] {type}", conn))
                        cmd.ExecuteNonQuery();
                }
            }
        }
        private static object ToDbDouble(string s)
        {
            if (string.IsNullOrWhiteSpace(s)) return DBNull.Value;
            // 두 문화권 모두 시도 (., ,)
            if (double.TryParse(s, NumberStyles.Any, CultureInfo.InvariantCulture, out var v)) return v;
            if (double.TryParse(s, NumberStyles.Any, CultureInfo.CurrentCulture, out v)) return v;
            return DBNull.Value;
        }
        private static void AddParam(OleDbCommand cmd, string name, object value, OleDbType type)
        {
            var p = cmd.CreateParameter();
            p.ParameterName = name;   // OleDb에선 이름 무시되지만 가독성을 위해 남김
            p.OleDbType = type;
            p.Value = value ?? DBNull.Value;
            cmd.Parameters.Add(p);
        }

