            var sp = sender as SerialPort;
            if (sp == null) return;
            string response = sp.ReadLine();
            if (response.Length > 0 && response[0] == '\u0005')
            {
                //01,08,-1254,-2801,+0000,+0000,+0000,+0000,+0000,+0000@@ //들어오는 데이터                      

                string cleaned = response.Trim('\u0005', '\r', '\n');
                string[] parts = cleaned.Split(',');
                if (parts.Length > 2)
                {
                    string target1 = parts[2];
                    string target2 = parts[3];

                    if (sp == SerialLvdt)
                    {
                        ValueLvdt1 = double.Parse(target1) / 1000;
                        ValueLvdt2 = double.Parse(target2) / 1000;
                        UpdateLvdtValue(srcLbLvdtL, ValueLvdt1);
                        UpdateLvdtValue(srcLbLvdtR, ValueLvdt2);
                    }
                }
            }
        }

        // UI 업데이트 공용 메서드
        private void UpdateLvdtValue(System.Windows.Forms.Label label, double value)
        {
            if (label.InvokeRequired)
            {
                label.Invoke(new Action(() => label.Text = $"{value:F3}"));
            }
            else
            {
                label.Text = $"{value:F3}";
            }
        }

        // ESP32 엔코더 각도 수신 이벤트 핸들러
        // ESP32 deg 무시, C#에서 cnt 기반 직접 계산 (4096 CPR = 1024PPR × 4x)
        private const double ESP32_COUNTS_PER_REV = 4096.0;
        private void Esp32Encoder_AngleReceived(double deg, int cnt)
        {
            // [임시] BSS138 5V 레벨컨버터로 24V 엔코더(E40H8-1024-3-T-24) 신호 수신 시
            // 펄스 누락으로 실제 각도의 약 50%만 측정됨. ×2 보정 적용.
            // → E40H8-1024-3-T-5 (5V 엔코더) 교체 또는 전압분배기(20KΩ+3.3KΩ) 적용 후 ×2 제거 필요
            ValueAngleZ = cnt / ESP32_COUNTS_PER_REV * 360.0 * 1.3;

            if (srcLbAngle != null)
            {
                UpdateAngleValue(srcLbAngle, ValueAngleZ);
            }
        }


        // 각도 값 UI 업데이트 메서드
        private void UpdateAngleValue(System.Windows.Forms.Label label, double value)
        {
            if (label != null && label.IsHandleCreated)
            {
                if (label.InvokeRequired)
                {
                    label.BeginInvoke(new Action(() => label.Text = $"{value:F3}°"));
                }
                else
                {
                    label.Text = $"{value:F3}°";
                }
            }
        }


    }

