        // Phase 4: 로그 레벨을 지정할 수 있는 오버로드 추가
        public void AppendLog(LogLevel level, string msg)
        {
            string line = $"[{DateTime.Now:HH:mm:ss}][{wStep}][{level.ToString().ToUpper()}] {msg}";
            _logQueue.Add(line);  // ← 매우 빠름 (비동기)

