        public void BeginMeasurement()
        {
            string[] channels = { "Dev1/ai0" };

            // 2. 모니터 객체 생성
            _monitor = new NoiseVoltageMonitor(
                channels,
                sampleRate_Hz: 1000,   // 샘플링 속도
                samplesPerRead: 100,   // 콜백당 샘플 수 (~100ms)
                voltMin: 0.0,          // 전압 최소 범위
                voltMax: 10.0,          // 전압 최대 범위
                termCfg: NationalInstruments.DAQmx.AITerminalConfiguration.Differential,
                logger: AppendLog        // 로그 콜백 (아래 메서드)
            );
