        /// <summary>
        /// 스위치 작동 시점의 각도값 찾기 (선형 보간 사용)
        /// </summary>
        private double GetAngleAtTime(List<Sample> samples, double targetTime)
        {
            if (samples == null || samples.Count < 2)
                return 0;

            // targetTime과 가장 가까운 샘플 찾기
            Sample? beforeSample = null;
            Sample? afterSample = null;

            foreach (var sample in samples)
            {
                if (sample.t <= targetTime)
                {
                    beforeSample = sample;
                }
                else if (afterSample == null && sample.t > targetTime)
                {
                    afterSample = sample;
                    break;
                }
            }

            // 정확히 일치하는 샘플이 있으면 그 값 사용
            if (beforeSample.HasValue && Math.Abs(beforeSample.Value.t - targetTime) < 0.001)
            {
                return beforeSample.Value.v;
            }

            // 선형 보간
            if (beforeSample.HasValue && afterSample.HasValue)
            {
                double t1 = beforeSample.Value.t;
                double v1 = beforeSample.Value.v;
                double t2 = afterSample.Value.t;
                double v2 = afterSample.Value.v;

                if (t2 != t1)
                {
                    double ratio = (targetTime - t1) / (t2 - t1);
                    return v1 + ratio * (v2 - v1);
                }
            }

            // beforeSample만 있으면 그 값 사용
            if (beforeSample.HasValue)
            {
                return beforeSample.Value.v;
            }

            return 0;
        }

        /// <summary>
        /// 각도 변화량 그래프가 스위치 접촉 각도 계산값에 도달하는 시점(X축 값) 및 각도값(Y축 값) 계산
        /// </summary>
        private double CalculateIntersectionTime(List<Sample> samples, double firstNonZeroTime, double targetAngle, out double intersectionAngle)
        {
            intersectionAngle = 0;

            if (samples == null || samples.Count < 2)
            {
                return 0;
            }

            // targetAngle과 교차하는 구간 찾기
            Sample? beforeSample = null;
            Sample? afterSample = null;

            foreach (var sample in samples)
            {
                double adjustedTime = sample.t - firstNonZeroTime;
                if (adjustedTime < 0) continue;

                if (sample.v <= targetAngle)
                {
                    beforeSample = sample;
                }
                else if (afterSample == null && sample.v > targetAngle)
                {
                    afterSample = sample;
                    break;
                }
            }

            if (beforeSample == null || afterSample == null)
            {
                return 0;
            }

            // 선형 보간으로 교점의 X값(시간) 및 Y값(각도) 계산
            double t1 = beforeSample.Value.t - firstNonZeroTime;
            double v1 = beforeSample.Value.v;
            double t2 = afterSample.Value.t - firstNonZeroTime;
            double v2 = afterSample.Value.v;

            if (v1 <= targetAngle && v2 >= targetAngle && v2 != v1)
            {
                // 선형 보간: t = t1 + (targetAngle - v1) / (v2 - v1) * (t2 - t1)
                double ratio = (targetAngle - v1) / (v2 - v1);
                double intersectionTime = t1 + ratio * (t2 - t1);

                // 교점의 Y값(각도)은 선형 보간으로 계산 (더 정확한 값)
                intersectionAngle = v1 + ratio * (v2 - v1);

                return intersectionTime;
            }

            return 0;
        }

        private void NoiseCurrentTest(int OnSignal,
                                        ZedGraphControl NoiseGraph,
                                        ZedGraphControl CurrentGraph,
                                        ZedGraphControl ResistGraph,
                                        System.Windows.Forms.Label NoiseStVal, System.Windows.Forms.Label NoiseOpVal,
                                        System.Windows.Forms.Label CurrentStVal, System.Windows.Forms.Label CurrentOpVal,
                                        System.Windows.Forms.Label SpeedVal, System.Windows.Forms.Label ResistValMin, System.Windows.Forms.Label ResistValMax,
                                        System.Windows.Forms.Label NoiseStDec, System.Windows.Forms.Label NoiseOpDec,
                                        System.Windows.Forms.Label CurrentStDec, System.Windows.Forms.Label CurrentOpDec,
                                        System.Windows.Forms.Label SpeedDec, System.Windows.Forms.Label ResistDec,
                                        int testID)
        {
            var specs = ClassBasic.MotionSpec.LoadByTestId(testID);
            var Spec = specs?.FirstOrDefault();
            if (Spec == null)
            {
                AppendLog($"[ERR] Spec 없음: ID={testID}");
                return;
            }
            double tictime = 0;
            double t = 0;
            int intStopConCount = 0;
            int teststep = 0;
            double resistOperatingMax = 0.0, resistOperatingMin = 100.0;
            double currentStartMax = 0.0, currentOperatingMax = 0.0;
            double noiseStartMax = 0.0, noiseOperatingMax = 0.0;
            var noiseSamples = new List<Sample>(4096);
            var currentSamples = new List<Sample>(4096);
            var resistSamples = new List<Sample>(4096);

            // tmrWork는 계속 실행 (비상정지 체크를 위해)
            var swLocal = sw;
            bool running = true;

            // 타임아웃(예: 전체 60초 보호)
            var overallWatch = Stopwatch.StartNew();
            const double OVERALL_TIMEOUT_SEC = 60;
            teststep = 0;
            try
            {
                while (running)
                {
                    // 비상정지 체크 (Input 2가 false일 때 = 비상정지 버튼 B접)
                    if (!io.GetInput(2))
                    {
                        // 모든 IO 출력 OFF
                        for (int i = 0; i <= 29; i++)
                        {
                            io.Do_Off_Force(i);
                        }
                        io.Commit();

                        wStep = 2000;
                        if (PanelAlarm != null && LbAlarm != null)
                        {
                            PanelAlarm.Visible = true;
                            LbAlarm.Text = "비상정지 눌림! 해제후 리셋";
                        }
                        AppendLog("[비상정지] NoiseCurrentTest 중 비상정지 발생 - 모든 출력 OFF");
                        running = false; // 루프 종료
                        break;
                    }

                    // 전체 타임아웃 보호
                    if (overallWatch.Elapsed.TotalSeconds > OVERALL_TIMEOUT_SEC)
                    {
                        AppendLog("[WARN] TimeOut");
                        break;
                    }

                    switch (teststep)
                    {
                        case 0:
                            t = 0;
                            swLocal.Restart();
                            noiseSamples.Clear();
                            currentSamples.Clear();
                            currentStartMax = currentOperatingMax = 0.0;
                            noiseStartMax = noiseOperatingMax = 0.0;
                            AppendLog("Set Test Condition");
                            AppendLog("Test Start");
                            io.Do_On_Force(OnSignal);
                            io.Commit();
                            AppendLog($"Do_on({OnSignal.ToString()})");
                            teststep = 1;
                            break;

                        case 1: // 측정 수집
                            t = swLocal.Elapsed.TotalSeconds;
                            ClassZedGraph.DrawGraph(NoiseGraph, _monitor.Value, t);
                            ClassZedGraph.DrawGraph(CurrentGraph, _supply.ValueCurr, t);
                            ClassZedGraph.DrawGraph(ResistGraph, ValueResist, t);

                            resistSamples.Add(new Sample { t = t, v = ValueResist });
                            noiseSamples.Add(new Sample { t = t, v = _monitor.Value });
                            currentSamples.Add(new Sample { t = t, v = _supply.ValueCurr });

                            // 테스트 데이터 수집 (메모리에만 저장, 나중에 CSV로 저장)
                            if (OnSignal == 24) // CW
                            {
                                _testDataRecorder.AddCWSample(t, _monitor.Value, _supply.ValueCurr, ValueResist);
                            }
                            else if (OnSignal == 25) // CCW
                            {
                                _testDataRecorder.AddCCWSample(t, _monitor.Value, _supply.ValueCurr, ValueResist);
                            }

                            tictime = t;

                            if ((t > 2 && _supply.ValueCurr >= 9) ||
                                (t > 2 && _supply.ValueCurr <= 0.2))
                            {
                                AppendLog($"StopCondition:[{intStopConCount.ToString()}]");
                                intStopConCount++;
                            }
                            else
                            {
                                intStopConCount = 0;
                            }

                            if (intStopConCount > 10)
                            {
                                io.Do_Off_Force(OnSignal);
                                io.Commit();
                                AppendLog($"Do_off({OnSignal.ToString()})");
                                teststep = 2;
                            }
                            break;

                        case 2: // FWD 계산/표시

                            AppendLog("Decide");
                            t = swLocal.Elapsed.TotalSeconds;
                            double endT1 = Math.Max(0, t - 1.5); // 음수 방지

                            ClassZedGraph.AddGuideLines(
                                NoiseGraph,
                                new[] { Spec.StartUpNoiseMin, Spec.StartUpNoiseMax, Spec.MovingNoiseMin, Spec.MovingNoiseMax },
                                new[] { Spec.StartUpSector, endT1 },
                                Color.DarkGray, Color.DarkGray, 2.0f, DashStyle.Dash);

                            ClassZedGraph.AddGuideLines(
                                CurrentGraph,
                                new[] { Spec.StartUpAmpMin, Spec.StartUpAmpMax, Spec.MovingAmpMin, Spec.MovingAmpMax },
                                new[] { Spec.StartUpSector, endT1 },
                                Color.DarkGray, Color.DarkGray, 2.0f, DashStyle.Dash);

                            ClassZedGraph.AddGuideLines(
                                ResistGraph,
                                null,
                                new[] { 1.5, endT1 },
                                Color.DarkGray, Color.DarkGray, 2.0f, DashStyle.Dash);

                            foreach (var s in noiseSamples)
                            {
                                if (s.t <= Spec.StartUpSector) noiseStartMax = Math.Max(noiseStartMax, s.v);
                                else if (s.t <= endT1) noiseOperatingMax = Math.Max(noiseOperatingMax, s.v);
                            }
                            foreach (var s in currentSamples)
                            {
                                if (s.t <= Spec.StartUpSector) currentStartMax = Math.Max(currentStartMax, s.v);
                                else if (s.t <= endT1) currentOperatingMax = Math.Max(currentOperatingMax, s.v);
                            }

                            foreach (var s in resistSamples)
                            {
                                if (s.t >= 1.5 && s.t <= endT1)
                                {
                                    resistOperatingMax = Math.Max(resistOperatingMax, s.v);
                                    resistOperatingMin = Math.Min(resistOperatingMin, s.v);
                                }
                            }

                            NoiseStVal.Text = Math.Round(noiseStartMax, 2).ToString();
                            NoiseOpVal.Text = Math.Round(noiseOperatingMax, 2).ToString();
                            CurrentStVal.Text = Math.Round(currentStartMax, 2).ToString();
                            CurrentOpVal.Text = Math.Round(currentOperatingMax, 2).ToString();
                            SpeedVal.Text = Math.Round(180 / (t + Spec.SpeedTimeTol), 2).ToString();

                            AppendLog($"Time 180도/{(t + Spec.SpeedTimeTol)}초");
                            AppendLog($"Time : 180도/{(t + Spec.SpeedTimeTol)}초");
                            AppendLog($"Speed : 180도/{(t + Spec.SpeedTimeTol)}초");

                            ResistValMin.Text = Math.Round(resistOperatingMin, 2).ToString();
                            ResistValMax.Text = Math.Round(resistOperatingMax, 2).ToString();

                            Decide(Spec.StartUpNoiseMin, Spec.StartUpNoiseMax, NoiseStVal, NoiseStDec);
                            Decide(Spec.MovingNoiseMin, Spec.MovingNoiseMax, NoiseOpVal, NoiseOpDec);
                            Decide(Spec.StartUpAmpMin, Spec.StartUpAmpMax, CurrentStVal, CurrentStDec);
                            Decide(Spec.MovingAmpMin, Spec.MovingAmpMax, CurrentOpVal, CurrentOpDec);
                            Decide(Spec.SpeedMin, Spec.SpeedMax, SpeedVal, SpeedDec);
                            if ((resistOperatingMin >= Spec.ResistMin) &&
                                (resistOperatingMin <= Spec.ResistMax) &&
                                (resistOperatingMax >= Spec.ResistMin) &&
                                (resistOperatingMax <= Spec.ResistMax))
                            {
                                ResistDec.Text = "OK";
                                ResistDec.BackColor = Color.Blue;
                            }
                            else
                            {
                                ResistDec.Text = "NG";
                                ResistDec.BackColor = Color.Red;
                            }

                            teststep = 3;
                            break;

                        case 3:

                            //io.Do_Off(Spec.TestIO);
                            running = false; // break;
                            break;

                    }

                    Thread.Sleep(10);
                    Application.DoEvents();
                }
            }
            finally
            {
                swLocal.Stop();
                // 비상정지 상태가 아니면 다음 단계로 진행
                if (wStep != 2000)
                {
                    if (OnSignal == 24) // CW 테스트
                    {
                        wStep = 201.5; // 180도 검사로 (이후 CCW 테스트)
                    }
                    else if (OnSignal == 25) // CCW 테스트
                    {
                        wStep = 203; // 테스트 완료로
                    }
                }
                // tmrWork는 계속 실행 중이므로 재시작 불필요
                // tmrWork.Interval = 100;
                // tmrWork.Start();
            }
        }

        private static int GetIntCol(DataRow row, string col)
        {
            if (row != null && row.Table.Columns.Contains(col) && row[col] != DBNull.Value)
            {
                int.TryParse(row[col].ToString(), out int val);
                return val;
            }
            return 0;
        }
        private static string GetCol(DataRow row, string col)
     => (row != null && row.Table.Columns.Contains(col) && row[col] != DBNull.Value)
        ? row[col].ToString()
        : string.Empty;
        public void InitPartsStore()
        {
            // Phase 3: Repository 사용
            if (_partsRepository != null)
            {
                _partsRepository.Refresh();
                var allParts = _partsRepository.GetAll();
                AppendLog($"[DB] Table_Part loaded. rows={allParts.Count}");
                return;
            }

            // 기존 코드 (호환성 유지)
            var accdbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, @"DB\DataBase_Setting.accdb");
            _partsConnStr = $"Provider=Microsoft.ACE.OLEDB.12.0;Data Source={accdbPath}";

            if (!File.Exists(accdbPath))
            {
                AppendLog("[ERR] ACCDB 파일이 없음: " + accdbPath);
                _partsTable = new DataTable(); // 빈 테이블로 유지
                return;
            }

            int rows = LoadPartsTable();
            AppendLog($"[DB] Table_Part loaded. rows={rows}");
        }
        private int LoadPartsTable()
        {
            var dt = new DataTable();

            using (var adp = new OleDbDataAdapter(
                "SELECT ID,TestID,BarcodeID,PartNo,PartName,CarType,Target_SW_Ver,Target_HW_Ver,ScanTarget,ControlType " +
                "FROM Table_Part ORDER BY PartNo ASC",
                _partsConnStr))
            {
                adp.MissingSchemaAction = MissingSchemaAction.Add;
                int rows = adp.Fill(dt);
                _partsTable = dt;
                return rows;
            }
        }

        private void EnsurePartsLoaded()
        {
            if (_partsTable == null || _partsTable.Rows.Count == 0)
            {
                AppendLog("[WARN] _partsTable 비어 있음 → 재로드");
                LoadPartsTable();
            }
        }
        private DataRow FindPartByBarcode(string scandata)
        {
            // Phase 3: Repository 사용
            if (_partsRepository != null)
            {
                var partInfo = _partsRepository.FindByBarcode(scandata);
                if (partInfo != null)
                {
                    // DataRow로 변환 (기존 코드 호환성)
                    return ConvertPartInfoToDataRow(partInfo);
                }
                return null;
            }

            // 기존 코드 (호환성 유지)
            EnsurePartsLoaded();

            if (_partsTable == null || !_partsTable.Columns.Contains("PartNo"))
                return null;

            string data = (scandata ?? string.Empty).Trim().Replace("'", "''");

            // '%...%' 패턴으로 LIKE 검색
            DataRow[] rows = _partsTable.Select($"'{data}' LIKE '%' + PartNo + '%'");
            return rows.Length > 0 ? rows[0] : null;
        }

        // Phase 3: PartInfo를 DataRow로 변환 (임시 호환성 메서드)
        private DataRow ConvertPartInfoToDataRow(PartInfo partInfo)
        {
            if (partInfo == null)
                return null;

            // 임시 DataTable 생성
            if (_partsTable == null)
            {
                _partsTable = new DataTable();
                _partsTable.Columns.Add("ID", typeof(int));
                _partsTable.Columns.Add("TestID", typeof(int));
                _partsTable.Columns.Add("BarcodeID", typeof(int));
                _partsTable.Columns.Add("PartNo", typeof(string));
                _partsTable.Columns.Add("PartName", typeof(string));
                _partsTable.Columns.Add("CarType", typeof(string));
                _partsTable.Columns.Add("Target_SW_Ver", typeof(string));
                _partsTable.Columns.Add("Target_HW_Ver", typeof(string));
                _partsTable.Columns.Add("ScanTarget", typeof(string));
                _partsTable.Columns.Add("ControlType", typeof(string));
            }

            var row = _partsTable.NewRow();
            row["ID"] = partInfo.Id;
            row["TestID"] = partInfo.TestId;
            row["BarcodeID"] = partInfo.BarcodeId;
            row["PartNo"] = partInfo.PartNo;
            row["PartName"] = partInfo.PartName;
            row["CarType"] = partInfo.CarType;
            row["Target_SW_Ver"] = partInfo.TargetSwVer;
            row["Target_HW_Ver"] = partInfo.TargetHwVer;
            row["ScanTarget"] = partInfo.ScanTarget;
            row["ControlType"] = partInfo.ControlType;
            _partsTable.Rows.Add(row);

            return row;
        }
        private void SerialScanner_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            try
            {
                string line = SerialScanner.ReadLine(); // CR/LF 기준 한 줄
                if (string.IsNullOrWhiteSpace(line)) return;

                this.BeginInvoke(new Action(() =>
                {

                    string tmpData = line.Trim();
                    string scandata = line.Trim();

                    AppendLog($"[SCAN] {scandata}");

                    // wStep 710: 바코드 스캔 검증 (출력된 바코드와 비교)
                    if (wStep == 710)
                    {
                        _scannedBarcode = scandata;
                        AppendLog($"[SCAN] 바코드 스캔: {scandata}");

                        // gBarcodeTMp와 비교 (스캐너가 읽는 형식)
                        if (!string.IsNullOrEmpty(gBarcodeTMp))
                        {
                            if (scandata.Contains(gBarcodeTMp) || gBarcodeTMp.Contains(scandata) || scandata == gBarcodeTMp)
                            {
                                _barcodeScanOk = true;
                                AppendLog($"[SCAN] 바코드 검증 OK: {scandata} == {gBarcodeTMp}");
                            }
                            else
                            {
                                _barcodeScanOk = false;
                                AppendLog($"[SCAN] 바코드 검증 NG: {scandata} != {gBarcodeTMp} (재스캔 필요)");
                            }
                        }
                        else if (!string.IsNullOrEmpty(gEndBarcode))
                        {
                            // gBarcodeTMp가 없으면 gEndBarcode와 비교
                            if (scandata.Contains(gEndBarcode) || gEndBarcode.Contains(scandata) || scandata == gEndBarcode)
                            {
                                _barcodeScanOk = true;
                                AppendLog($"[SCAN] 바코드 검증 OK: {scandata} == {gEndBarcode}");
                            }
                            else
                            {
                                _barcodeScanOk = false;
                                AppendLog($"[SCAN] 바코드 검증 NG: {scandata} != {gEndBarcode} (재스캔 필요)");
                            }
                        }
                        else
                        {
                            AppendLog($"[WARN] 바코드 데이터가 없습니다. 바코드가 출력되었는지 확인하세요.");
                            _barcodeScanOk = false;
                        }
                        return;  // 바코드 검증 처리 후 종료
                    }

                    if (wStep == 0)
                    {

                        DataRow partRow = FindPartByBarcode(scandata);
                        if (partRow != null)
                        {
                            InitControl();
                            AppendLog("Reset and Start");
                            // 전역 변수 채우기
                            gPartNo = GetCol(partRow, "PartNo");
                            srclbPartNo.Text = gPartNo;
                            AppendLog($"Part:{gPartNo}");
                            gPartName = GetCol(partRow, "PartName");
                            srclbPartName.Text = gPartName;
                            gTestID = GetIntCol(partRow, "TestID");
                            gBarcodeID = GetIntCol(partRow, "BarcodeID");
                            srclbSerial.Text = scandata;
                            gSerialNo = srclbSerial.Text;  // SerialNo 변수에 할당
                            gYMD = MidString(scandata, 3, 6);
                            gLot = MidString(scandata, 9, 7);
                            // UI 반영
                            AppendLog($"[PART] {gPartNo} → {gPartName}, {gCarType}");

                            // Phase 2: 상태 머신 사용
                            if (_testController != null && _workContext != null)
                            {
                                _workContext.TestID = gTestID;
                                _workContext.PartNo = gPartNo;
                                _workContext.PartName = gPartName;
                                _workContext.SerialNo = scandata;
                                _testController.SetState(WorkState.ScanComplete);
