        /// <summary>
        /// 두 LVDT 값과 간격으로 기울기(도)를 계산해 소수점 둘째 자리까지 반올림해 반환.
        /// 왼쪽이 더 높으면 +각.
        /// </summary>
        public static double ComputeTiltDeg(double lvdtLeft, double lvdtRight, double baseline)
        {
            if (!(baseline > 0.0)) throw new ArgumentOutOfRangeException(nameof(baseline), "baseline must be > 0");

            double delta = lvdtLeft - lvdtRight;
            double rad = Math.Atan2(delta, baseline);
            double deg = rad * (180.0 / Math.PI);

            // 소수점 둘째 자리 반올림 (은행가 반올림 피하기 위해 AwayFromZero)
            double rounded = Math.Round(deg, 2, MidpointRounding.AwayFromZero);
            // -0.00 방지
            if (rounded == 0) rounded = 0.0;

            return rounded;
        }

